mapper.select:
/* SQL ID : TermDAO.selectListHomeTermStatus 설 명 : 마이페이지 > 수강, 강의 리스트(학기부분에서 사용) */ SELECT ROW_NUMBER() OVER(ORDER BY DGRS_YR DESC, DGRS_SMSTR DESC, SMSTRNM) AS LINE_NO , CRS_SMSTR_ID , SMSTRNM , ORG_ID , DGRS_YR , DGRS_SMSTR , SMSTR_TYCD , SMSTR_STSCD FROM CRS_SMSTR A WHERE 1 = 1 AND SMSTR_STSCD = #{termStatus}
AND SMSTR_TYCD = #{termType}
ORDER BY LINE_NO DESC

/* SQL ID : TermDAO.list 설 명 : 학기 모든 목록 조회(비정규, 정규) */ SELECT ROW_NUMBER() OVER(ORDER BY TERM_ORDER, DGRS_YR DESC, DGRS_SMSTR DESC, TERM_ORDER2) AS LINE_NO , A.* FROM ( SELECT CRS_SMSTR_ID , SMSTRNM , ORG_ID , DGRS_YR , DGRS_SMSTR , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'DGRS_SMSTR' AND CD = A.DGRS_SMSTR) AS HAKSA_TERM_NM , SMSTR_TYCD , OFLN_LRN_MNGYN , SMSTR_STSCD , SMSTR_DATA_LNKGYN , OP_SDTTM , OP_EDTTM , ATNDLC_APLY_SDTTM , ATNDLC_APLY_EDTTM , ATNDLC_MOD_SDTTM , ATNDLC_MOD_EDTTM , ATNDLC_SDTTM , ATNDLC_EDTTM , SCR_EVL_SDTTM , SCR_EVL_EDTTM , SCR_OPEN_SDTTM , SCR_OPEN_EDTTM , SCR_CALC_CTGRCD , MBL_ATNDC_USEYN , NOW_SMSTRYN , (CASE WHEN SMSTR_STSCD ='SERVICE' THEN 1 WHEN SMSTR_STSCD = 'WAIT' THEN 2 WHEN SMSTR_STSCD = 'FINISH' THEN 3 ELSE 4 END) AS TERM_ORDER , (CASE WHEN SMSTR_TYCD ='NORMAL' THEN 1 WHEN SMSTR_STSCD ='BNORMAL' THEN 2 WHEN SMSTR_STSCD = 'OPEN' THEN 3 ELSE 4 END) AS TERM_ORDER2 , (SELECT COUNT(1) FROM TB_LMS_TERM_CRE_CRS_RLTN WHERE A.CRS_SMSTR_ID = CRS_SMSTR_ID) AS CRS_COUNT , COUNT(1) OVER() AS TOTAL_CNT , RGTR_ID , FRST_INQ_DTTM , MDFR_ID , MOD_DTTM FROM CRS_SMSTR A WHERE ORG_ID = #{orgId} AND DGRS_SMSTR IN ('10', '20', '11', '21')
AND SMSTR_TYCD = #{termType}
) A ORDER BY LINE_NO

/* SQL ID : TermDAO.listHaksaTerm 설 명 : 학기 모든 목록 조회 */ SELECT A.DGRS_YR, A.DGRS_SMSTR, (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'DGRS_SMSTR' AND CD = A.DGRS_SMSTR) AS HAKSA_TERM_NM, A.NOW_SMSTRYN FROM CRS_SMSTR A WHERE ORG_ID = #{orgId}
AND A.DGRS_YR = #{haksaYear}
GROUP BY A.DGRS_YR, A.DGRS_SMSTR, A.NOW_SMSTRYN ORDER BY A.DGRS_YR DESC, A.DGRS_SMSTR

/* SQL ID : TermDAO.selectTermListPage 설 명 : 학기 모든 목록 조회(비정규, 정규) */
SELECT ROW_NUMBER() OVER(ORDER BY TERM_ORDER, DGRS_YR DESC, DGRS_SMSTR DESC, TERM_ORDER2) AS LINE_NO , A.* FROM ( SELECT CRS_SMSTR_ID , SMSTRNM , ORG_ID , DGRS_YR , DGRS_SMSTR , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'DGRS_SMSTR' AND CD = A.DGRS_SMSTR) AS HAKSA_TERM_NM , SMSTR_TYCD , OFLN_LRN_MNGYN , SMSTR_STSCD , SMSTR_DATA_LNKGYN , OP_SDTTM , OP_EDTTM , ATNDLC_APLY_SDTTM , ATNDLC_APLY_EDTTM , ATNDLC_MOD_SDTTM , ATNDLC_MOD_EDTTM , ATNDLC_SDTTM , ATNDLC_EDTTM , SCR_EVL_SDTTM , SCR_EVL_EDTTM , SCR_OPEN_SDTTM , SCR_OPEN_EDTTM , SCR_CALC_CTGRCD , MBL_ATNDC_USEYN , NOW_SMSTRYN , (CASE WHEN SMSTR_STSCD ='SERVICE' THEN 1 WHEN SMSTR_STSCD = 'WAIT' THEN 2 WHEN SMSTR_STSCD = 'FINISH' THEN 3 ELSE 4 END) AS TERM_ORDER , (CASE WHEN SMSTR_TYCD ='NORMAL' THEN 1 WHEN SMSTR_STSCD ='BNORMAL' THEN 2 WHEN SMSTR_STSCD ='OPEN' THEN 3 ELSE 4 END) AS TERM_ORDER2 , RGTR_ID , FRST_INQ_DTTM , MDFR_ID , MOD_DTTM FROM CRS_SMSTR A WHERE 1 = 1
AND SMSTR_TYCD = #{termType}
AND LOWER(SMSTRNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
) A ORDER BY LINE_NO

/* SQL ID : TermDAO.selectListStatus 설 명 : 법정교육, 공개강좌 학기 리스트 */ SELECT ROW_NUMBER() OVER(ORDER BY DGRS_YR DESC, DGRS_SMSTR, TERM_ORDER, TERM_ORDER2) AS LINE_NO , A.* FROM ( SELECT CRS_SMSTR_ID , SMSTRNM , ORG_ID , DGRS_YR , DGRS_SMSTR , SMSTR_TYCD , SMSTR_STSCD , ( CASE WHEN SMSTR_STSCD ='SERVICE' THEN 1 WHEN SMSTR_STSCD = 'WAIT' THEN 2 WHEN SMSTR_STSCD = 'FINISH' THEN 3 ELSE 4 END ) AS TERM_ORDER , ( CASE WHEN SMSTR_TYCD ='NORMAL' THEN 1 WHEN SMSTR_STSCD ='BNORMAL' THEN 2 WHEN SMSTR_STSCD = 'OPEN' THEN 3 ELSE 4 END ) AS TERM_ORDER2 FROM CRS_SMSTR A WHERE 1 = 1 AND SMSTR_STSCD != 'FINISH'
AND SMSTR_TYCD = #{termType}
AND (DGRS_YR, DGRS_SMSTR) IN ( SELECT SBJCT_ID, CRS_ID FROM TB_LMS_SBJCT WHERE SBJCT_ID = #{crsCreCd} )
) A ORDER BY DGRS_YR DESC, DGRS_SMSTR, TERM_ORDER, TERM_ORDER2

/* SQL ID : TermDAO.selectListTermStatus 설 명 : 종료가 아닌 학기 리스트 */ SELECT ROW_NUMBER() OVER(ORDER BY TERM_ORDER, DGRS_YR DESC, DGRS_SMSTR DESC, TERM_ORDER2) AS LINE_NO , A.* FROM ( SELECT ORG_SMSTR_COHORT_ID AS TERM_CD , SMSTR_COHORTNM AS TERM_NM , ORG_ID , DGRS_YR AS HAKSA_YEAR , DGRS_SMSTR_COHORT AS HAKSA_TERM , SMSTR_COHORT_TYCD AS TERM_TYPE , SMSTR_COHORT_STSCD AS TERM_STATUS , (CASE WHEN SMSTR_COHORT_STSCD ='SERVICE' THEN 1 WHEN SMSTR_COHORT_STSCD ='WAIT' THEN 2 WHEN SMSTR_COHORT_STSCD ='FINISH' THEN 3 ELSE 4 END) AS TERM_ORDER , (CASE WHEN SMSTR_COHORT_STSCD ='NORMAL' THEN 1 WHEN SMSTR_COHORT_STSCD ='BNORMAL' THEN 2 WHEN SMSTR_COHORT_STSCD ='OPEN' THEN 3 ELSE 4 END) AS TERM_ORDER2 FROM CRS_SMSTR A WHERE 1 = 1 AND SMSTR_STSCD != 'FINISH'
AND SMSTR_TYCD = #{termType}
AND CRS_SMSTR_ID IN ( SELECT DISTINCT(CRS_SMSTR_ID) FROM TB_LMS_TERM_CRE_CRS_RLTN WHERE SBJCT_ID IN
#{item}
)
) A ORDER BY LINE_NO DESC

/* SQL ID : TermDAO.selectListTermRltn 설 명 : 학기 조인 목록 */ SELECT A.CRS_SMSTR_ID , A.SMSTRNM , A.ORG_ID , A.DGRS_YR , A.DGRS_SMSTR , A.SMSTR_TYCD , A.OFLN_LRN_MNGYN , A.SMSTR_STSCD , A.OP_SDTTM , A.OP_EDTTM , A.ATNDLC_APLY_SDTTM , A.ATNDLC_APLY_EDTTM , A.ATNDLC_MOD_SDTTM , A.ATNDLC_MOD_EDTTM , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.SCR_EVL_SDTTM , A.SCR_EVL_EDTTM , A.SCR_OPEN_SDTTM , A.SCR_OPEN_EDTTM , A.SCR_CALC_CTGRCD , A.MBL_ATNDC_USEYN , A.NOW_SMSTRYN , (CASE WHEN A.SMSTR_STSCD ='SERVICE' THEN 1 WHEN A.SMSTR_STSCD = 'WAIT' THEN 2 WHEN A.SMSTR_STSCD='FINISH' THEN 3 ELSE 4 END) AS TERM_ORDER , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM FROM CRS_SMSTR A , TB_LMS_TERM_CRE_CRS_RLTN B WHERE A.CRS_SMSTR_ID = B.CRS_SMSTR_ID
AND B.SBJCT_ID = #{crsCreCd}
ORDER BY TERM_ORDER, DGRS_YR DESC, DGRS_SMSTR DESC

/*
	 SQL ID : TermDAO.countPageing
	 설  명 : 학기 카운트 조회(비정규, 정규)
*/
SELECT COUNT(ORG_SMSTR_COHORT_ID)
  FROM TB_LMS_ORG_SMSTR_COHORT
 WHERE 1 = 1
AND SMSTR_TYCD = #{termType}
AND SMSTR_STSCD = #{termStatus}
AND DGRS_YR = #{haksaYear}
AND ORG_ID = #{orgId}
AND LOWER(SMSTRNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))

mapper.update:
/*
	 SQL ID : TermDAO.editCurTermYn
	 설  명 :
*/
UPDATE CRS_SMSTR
   SET NOW_SMSTRYN = #{useYn}
	   , MDFR_ID = #{mdfrId}
	   , MOD_DTTM = FN_DTTM()
 WHERE CRS_SMSTR_ID = #{termCd}
 AND ORG_ID = #{orgId}

mapper.delete:
/*
	 SQL ID : TermDAO.deleteTermLesson
	 설  명 : 학기 정보 삭제 시 하위 학기 주차 삭제
*/

	DELETE FROM CRS_SMSTR_WKNO WHERE CRS_SMSTR_ID = #{termCd}

/*
	 SQL ID : TermDAO.delete
	 설  명 : 학기 정보 삭제
*/

DELETE FROM CRS_SMSTR WHERE CRS_SMSTR_ID = #{termCd}

mapper.select:
/*
	 SQL ID : TermDAO.crsTermCheck
	 설  명 : 학기 정보 등록 하기 전에 중복 체크 (정규과정에 학사년도, 학기 비교)
*/
SELECT  COUNT(CRS_SMSTR_ID) AS COUNT
  FROM CRS_SMSTR
 WHERE SMSTR_TYCD = #{termType}
   AND DGRS_YR = #{haksaYear}
   AND DGRS_SMSTR = #{haksaTerm}

mapper.update:
/*
	 SQL ID : TermDAO.update
	 설  명 : 학기 정보 수정
*/
UPDATE CRS_SMSTR
   SET SMSTRNM = #{termNm}

		, DGRS_YR = #{haksaYear}


		, DGRS_SMSTR = #{haksaTerm}


		, SMSTR_TYCD  = #{termType}


		, OFLN_LRN_MNGYN = #{offLessonMgtYn}


		, SMSTR_STSCD =  #{termStatus}


		, SMSTR_DATA_LNKGYN = #{termLinkYn}


		, OP_SDTTM = TO_CHAR(TO_DATE(#{svcStartDttm},'YYYYMMDDHH24MISS'),'YYYYMMDDHH24MISS')


		, OP_EDTTM = TO_CHAR(TO_DATE(#{svcEndDttm},'YYYYMMDDHH24MISS'),'YYYYMMDDHH24MISS')


		, ATNDLC_APLY_SDTTM = TO_CHAR(TO_DATE(#{enrlAplcStartDttm},'YYYYMMDDHH24MISS'),'YYYYMMDDHH24MISS')


		, ATNDLC_APLY_EDTTM = TO_CHAR(TO_DATE(#{enrlAplcEndDttm},'YYYYMMDDHH24MISS'),'YYYYMMDDHH24MISS')


		, ATNDLC_MOD_SDTTM = TO_CHAR(TO_DATE(#{enrlModStartDttm},'YYYYMMDDHH24MISS'),'YYYYMMDDHH24MISS')


		, ATNDLC_MOD_EDTTM = TO_CHAR(TO_DATE(#{enrlModEndDttm},'YYYYMMDDHH24MISS'),'YYYYMMDDHH24MISS')


		, ATNDLC_SDTTM = TO_CHAR(TO_DATE(#{enrlStartDttm},'YYYYMMDDHH24MISS'),'YYYYMMDDHH24MISS')



		, ATNDLC_EDTTM = TO_CHAR(TO_DATE(#{enrlEndDttm},'YYYYMMDDHH24MISS'),'YYYYMMDDHH24MISS')


		, SCR_EVL_SDTTM = TO_CHAR(TO_DATE(#{scoreEvalStartDttm},'YYYYMMDDHH24MISS'),'YYYYMMDDHH24MISS')


		, SCR_EVL_EDTTM = TO_CHAR(TO_DATE(#{scoreEvalEndDttm},'YYYYMMDDHH24MISS'),'YYYYMMDDHH24MISS')


		, SCR_OPEN_SDTTM = TO_CHAR(TO_DATE(#{scoreOpenStartDttm},'YYYYMMDDHH24MISS'),'YYYYMMDDHH24MISS')


		, SCR_OPEN_EDTTM = TO_CHAR(TO_DATE(#{scoreOpenEndDttm},'YYYYMMDDHH24MISS'),'YYYYMMDDHH24MISS')

	 , MDFR_ID =  #{mdfrId}
	 , MOD_DTTM =  FN_DTTM()
 WHERE CRS_SMSTR_ID = #{termCd}

mapper.insert:
/* SQL ID : TermDAO.mergeTermLessonList 설 명 : 학기 주차 설정 저장 */
MERGE INTO TB_LMS_SMSTR_COHORT_SCHDL T USING (
SELECT #{item.termCd} AS SMSTR_COHORT_SCHDL_ID , #{item.termCd} AS ORG_SMSTR_COHORT_ID , #{item.enrlType} AS LCTR_TYCD , #{item.lsnOdr} AS TOC_SEQ , #{item.startDt} AS SYMD , #{item.endDt} AS EYMD , #{item.ltDetmFrDt} AS LCTR_RCG_SYMD , #{item.ltDetmToDt} AS LCTR_RCG_EYMD , #{item.rgtrId} AS RGTR_ID , #{item.mdfrId} AS MDFR_ID FROM dual
) S ON (S.SMSTR_COHORT_SCHDL_ID = T.SMSTR_COHORT_SCHDL_ID AND S.TOC_SEQ = T.TOC_SEQ AND S.LCTR_TYCD = T.ATNDLC_TYCD) WHEN MATCHED THEN UPDATE SET SYMD = S.SYMD , EYMD = S.EYMD , LCTR_RCG_SYMD = S.LCTR_RCG_SYMD , LCTR_RCG_EYMD = S.LCTR_RCG_EYMD , MDFR_ID = S.MDFR_ID , MOD_DTTM = FN_DTTM() WHEN NOT MATCHED THEN INSERT ( SMSTR_COHORT_SCHDL_ID , ORG_SMSTR_COHORT_ID , ATNDLC_TYCD , TOC_SEQ , SYMD , EYMD , LCTR_RCG_SYMD , LCTR_RCG_EYMD , RGTR_ID , REG_DTTM , MDFR_ID , MOD_DTTM ) VALUES ( S.SMSTR_COHORT_SCHDL_ID , S.ORG_SMSTR_COHORT_ID , S.LCTR_TYCD , S.TOC_SEQ , S.SYMD , S.EYMD , S.LCTR_RCG_SYMD , S.LCTR_RCG_EYMD , S.RGTR_ID , FN_DTTM() , S.MDFR_ID , FN_DTTM() )

/*
	 SQL ID : TermDAO.deleteTermLessonNotInclude
	 설  명 : 학기 주차 설정 미사용 목록 삭제
*/
DELETE FROM TB_LMS_SMSTR_COHORT_SCHDL
WHERE SMSTR_COHORT_SCHDL_ID = #{termCd}
AND ATNDLC_TYCD = #{enrlType}
AND TOC_SEQ NOT IN

	#{item}

mapper.select:
/* SQL ID : TermDAO.view 설 명 : 학기 조회 */
SELECT CRS_SMSTR_ID , SMSTRNM , ORG_ID , DGRS_YR , DGRS_SMSTR , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'DGRS_SMSTR' AND CD = DGRS_SMSTR) AS HAKSA_TERM_NM , SMSTR_TYCD , OFLN_LRN_MNGYN , SMSTR_STSCD , SMSTR_DATA_LNKGYN , OP_SDTTM , OP_EDTTM , ATNDLC_APLY_SDTTM , ATNDLC_APLY_EDTTM , ATNDLC_MOD_SDTTM , ATNDLC_MOD_EDTTM , ATNDLC_SDTTM , ATNDLC_EDTTM , SCR_EVL_SDTTM , SCR_EVL_EDTTM , SCR_OPEN_SDTTM , SCR_OPEN_EDTTM , SCR_CALC_CTGRCD , MBL_ATNDC_USEYN , RGTR_ID , FRST_INQ_DTTM , MDFR_ID , MOD_DTTM FROM CRS_SMSTR WHERE CRS_SMSTR_ID = #{termCd}
AND ORG_ID = #{orgId}

/* SQL ID : TermDAO.listTermStatus 설 명 : 종료가 아닌 학기 리스트 */ SELECT ROW_NUMBER() OVER(ORDER BY DGRS_YR DESC, DGRS_SMSTR_COHORT DESC) AS LINE_NO , ORG_SMSTR_COHORT_ID AS TERM_CD , SMSTR_COHORTNM AS TERM_NM , ORG_ID , DGRS_YR AS HAKSA_YEAR , DGRS_SMSTR_COHORT AS HAKSA_TERM , SMSTR_COHORT_TYCD AS TERM_TYPE , SMSTR_COHORT_STSCD AS TERM_STATUS , (CASE WHEN SMSTR_COHORT_STSCD ='SERVICE' THEN 1 WHEN SMSTR_COHORT_STSCD ='WAIT' THEN 2 WHEN SMSTR_COHORT_STSCD ='FINISH' THEN 3 ELSE 4 END) AS TERM_ORDER , (CASE WHEN SMSTR_COHORT_STSCD ='NORMAL' THEN 1 WHEN SMSTR_COHORT_STSCD ='BNORMAL' THEN 2 WHEN SMSTR_COHORT_STSCD ='OPEN' THEN 3 ELSE 4 END) AS TERM_ORDER2 --, FN_GET_ORG_CODE_NM(ORG_ID,'CRS_OPER_UNI_CD', SMSTR_COHORT_STSCD ) TERM_TYPE_NM FROM TB_LMS_ORG_SMSTR_COHORT A WHERE 1 = 1 AND SMSTR_COHORT_STSCD != 'FINISH'
AND SMSTR_TYCD = #{termType}
AND CRS_SMSTR_ID IN (SELECT DISTINCT(CRS_SMSTR_ID) FROM TB_LMS_TERM_CRE_CRS_RLTN WHERE SBJCT_ID IN
#{item}
)
AND A.ORG_ID = #{orgId}
ORDER BY LINE_NO ${searchSort}DESC

/* SQL ID : TermDAO.listTermRltn 설 명 : 학기 조인 목록 */ SELECT A.CRS_SMSTR_ID , A.SMSTRNM , A.ORG_ID , A.DGRS_YR , A.DGRS_SMSTR , A.SMSTR_TYCD , A.OFLN_LRN_MNGYN , A.SMSTR_STSCD , A.OP_SDTTM , A.OP_EDTTM , A.ATNDLC_APLY_SDTTM , A.ATNDLC_APLY_EDTTM , A.ATNDLC_MOD_SDTTM , A.ATNDLC_MOD_EDTTM , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.SCR_EVL_SDTTM , A.SCR_EVL_EDTTM , A.SCR_OPEN_SDTTM , A.SCR_OPEN_EDTTM , A.SCR_CALC_CTGRCD , A.MBL_ATNDC_USEYN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM , (CASE WHEN A.SMSTR_STSCD ='SERVICE' THEN 1 WHEN A.SMSTR_STSCD = 'WAIT' THEN 2 WHEN A.SMSTR_STSCD='FINISH' THEN 3 ELSE 4 END) AS TERM_ORDER, FN_GET_ORG_CODE_NM(A.ORG_ID,'CRS_OPER_UNI_CD', A.SMSTR_TYCD) TERM_TYPE_NM FROM TB_LMS_ORG_SMSTR_COHORT A, TB_LMS_TERM_CRE_CRS_RLTN B WHERE A.CRS_SMSTR_ID = B.CRS_SMSTR_ID
AND B.SBJCT_ID = #{crsCreCd}
AND A.ORG_ID = #{orgId}
ORDER BY TERM_ORDER, DGRS_YR DESC, DGRS_SMSTR DESC

/* SQL ID : TermDAO.listPaging 설 명 : 학기 모든 목록 조회(비정규, 정규) */
SELECT ROW_NUMBER() OVER(ORDER BY TERM_ORDER, DGRS_YR DESC, DGRS_SMSTR DESC, TERM_ORDER2) AS LINE_NO , CRS_SMSTR_ID , SMSTRNM , ORG_ID , DGRS_YR , DGRS_SMSTR , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'DGRS_SMSTR' AND CD = A.DGRS_SMSTR) AS HAKSA_TERM_NM , SMSTR_TYCD , OFLN_LRN_MNGYN , SMSTR_STSCD , SMSTR_DATA_LNKGYN , OP_SDTTM , OP_EDTTM , ATNDLC_APLY_SDTTM , ATNDLC_APLY_EDTTM , ATNDLC_MOD_SDTTM , ATNDLC_MOD_EDTTM , ATNDLC_SDTTM , ATNDLC_EDTTM , SCR_EVL_SDTTM , SCR_EVL_EDTTM , SCR_OPEN_SDTTM , SCR_OPEN_EDTTM , SCR_CALC_CTGRCD , MBL_ATNDC_USEYN , RGTR_ID , FRST_INQ_DTTM , MDFR_ID , MOD_DTTM , (CASE WHEN SMSTR_STSCD ='SERVICE' THEN 1 WHEN SMSTR_STSCD='WAIT' THEN 2 WHEN SMSTR_STSCD='FINISH' THEN 3 ELSE 4 END) AS TERM_ORDER , (CASE WHEN SMSTR_TYCD ='NORMAL' THEN 1 WHEN SMSTR_TYCD='BNORMAL' THEN 2 WHEN SMSTR_TYCD='OPEN' THEN 3 ELSE 4 END) AS TERM_ORDER2 , (SELECT COUNT(*) FROM TB_LMS_TERM_CRE_CRS_RLTN WHERE A.CRS_SMSTR_ID = CRS_SMSTR_ID) AS COUNT , COUNT(1) OVER() AS TOTAL_CNT FROM CRS_SMSTR A WHERE 1 = 1
AND SMSTR_TYCD = #{termType}
AND SMSTR_STSCD = #{termStatus}
AND LOWER(SMSTRNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
AND ORG_ID = #{orgId}
ORDER BY LINE_NO

/* SQL ID : TermDAO.listCreYearByProf 설 명 : 교수자의 개설과목이 있는 개설년도 */
SELECT DISTINCT A.DGRS_YR FROM TB_LMS_SMSTR_CHRT A JOIN TB_LMS_SBJCT B ON A.SMSTR_CHRT_ID = B.SMSTR_CHRT_ID AND B.DELYN = 'N' AND B.USEYN = 'Y' AND B.ATNDLC_CERT_STSCD = 'APRV'
AND B.SBJCT_ID IN ( SELECT SBJCT_ID FROM TB_LMS_SBJCT_ADM WHERE USER_ID = #{userId}
AND ( SBJCT_ADM_TYCD = 'PROF' OR SBJCT_ADM_TYCD = 'TUT' )
AND SBJCT_ADM_TYCD = 'ASSI'
)
WHERE A.SMSTR_CHRT_STSCD != 'WAIT' ORDER BY A.DGRS_YR

/* SQL ID : TermDAO.listTermLesson 설 명 : 학기주차일정 목록 */ SELECT A.ORG_SMSTR_COHORT_ID -- , A.UNI_GBN , A.TOC_SEQ , A.ATNDLC_TYCD , A.SYMD , A.EYMD , A.LCTR_RCG_SYMD , A.LCTR_RCG_EYMD , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM FROM TB_LMS_SMSTR_COHORT_SCHDL A JOIN TB_LMS_ORG_SMSTR_COHORT B ON A.ORG_SMSTR_COHORT_ID = B.ORG_SMSTR_COHORT_ID AND B.ORG_ID = #{orgId}
AND B.DGRS_YR = #{haksaYear}
AND B.DGRS_SMSTR = #{haksaTerm}
AND B.CRS_SMSTR_ID = #{termCd}
WHERE A.ATNDLC_TYCD = 'ONLINE' ORDER BY A.TOC_SEQ
